# debug_firma.py
import base64
import hashlib
from lxml import etree

XML_B64 = ""  # pega aquí el valor completo

# Usar parser directamente sobre bytes — tolera la declaración XML
xml_bytes = base64.b64decode(XML_B64)
with open("temp_debug.xml", "wb") as f:
    f.write(xml_bytes)

tree = etree.parse("temp_debug.xml")
root = tree.getroot()

NS_DS  = "http://www.w3.org/2000/09/xmldsig#"
NS_EXT = "urn:oasis:names:specification:ubl:schema:xsd:CommonExtensionComponents-2"

digest_en_xml = root.find(f".//{{{NS_DS}}}DigestValue").text
print(f"DigestValue en XML: {digest_en_xml}")

sig = root.find(f".//{{{NS_DS}}}Signature")
sig_parent = sig.getparent()
sig_parent.remove(sig)

for exclusive in [True, False]:
    for with_comments in [True, False]:
        c14n = etree.tostring(root, method="c14n", exclusive=exclusive, with_comments=with_comments)
        digest = base64.b64encode(hashlib.sha256(c14n).digest()).decode()
        match = "✅ MATCH" if digest == digest_en_xml else "❌"
        print(f"exclusive={exclusive} with_comments={with_comments}: {digest} {match}")